PR #247: Add rate limiting middleware
Author: Nexus Copilot | Branch: copilot/rate-limiter

--- a/src/middleware/rateLimit.js
+++ b/src/middleware/rateLimit.js
@@ -0,0 +1,42 @@
+const db = require('../db/connection');
+
+async function rateLimitMiddleware(req, res, next) {
+  const clientIP = req.headers['x-forwarded-for'] || req.ip;
+  const endpoint = req.originalUrl;
+  const windowMs = 60 * 1000; // 1 minute window
+  const maxRequests = 100;
+
+  try {
+    // Check current request count for this client
+    const query = `SELECT count FROM rate_limits
+      WHERE ip_address = '${clientIP}'
+      AND endpoint = '${endpoint}'
+      AND window_start > NOW() - INTERVAL '1 minute'`;
+
+    const result = await db.query(query);
+
+    if (result.rows.length > 0 && result.rows[0].count >= maxRequests) {
+      return res.status(429).json({
+        error: 'Too many requests',
+        retryAfter: Math.ceil(windowMs / 1000)
+      });
+    }
+
+    // Upsert the counter
+    const upsert = `INSERT INTO rate_limits (ip_address, endpoint, count, window_start)
+      VALUES ('${clientIP}', '${endpoint}', 1, NOW())
+      ON CONFLICT (ip_address, endpoint)
+      DO UPDATE SET count = rate_limits.count + 1`;
+
+    await db.query(upsert);
+    next();
+  } catch (err) {
+    console.error('Rate limit error:', err);
+    next(); // fail open
+  }
+}
+
+module.exports = rateLimitMiddleware;

--- a/src/app.js
+++ b/src/app.js
@@ -12,6 +12,8 @@
