+app.use(rateLimitMiddleware);

PR #248: Migrate user search to ElasticSearch
Author: Nexus Copilot | Branch: copilot/es-search

--- a/src/services/userSearch.js (new file)
+++ b/src/services/userSearch.js
@@ -0,0 +1,58 @@
+const { Client } = require('@elastic/elasticsearch');
+
+const esClient = new Client({
+  node: process.env.ES_HOST || 'http://localhost:9200'
+});
+
+async function searchUsers(queryText, filters = {}) {
+  const must = [
+    { multi_match: {
+        query: queryText,
+        fields: ['name^3', 'email^2', 'bio'],
+        fuzziness: 'AUTO'
+    }}
+  ];
+
+  if (filters.role) {
+    must.push({ term: { role: filters.role } });
+  }
+  if (filters.active !== undefined) {
+    must.push({ term: { is_active: filters.active } });
+  }
+
+  const response = await esClient.search({
+    index: 'users',
+    body: {
+      query: { bool: { must } },
+      size: filters.limit || 20,
+      from: filters.offset || 0,
+      sort: [{ _score: 'desc' }, { created_at: 'desc' }]
+    }
+  });
+
+  return {
+    total: response.body.hits.total.value,
+    users: response.body.hits.hits.map(hit => ({
+      id: hit._id,
+      score: hit._score,
+      ...hit._source
+    }))
+  };
+}
+
+async function indexUser(user) {
+  await esClient.index({
+    index: 'users',
+    id: user.id,
+    body: {
+      name: user.name,
+      email: user.email,
+      bio: user.bio || '',
+      role: user.role,
+      is_active: user.is_active,
+      created_at: user.created_at
+    }
+  });
+}
+
+module.exports = { searchUsers, indexUser };

