PR #249: Fix pagination in /api/projects
Author: Nexus Copilot | Branch: copilot/fix-pagination

--- a/src/routes/projects.js
+++ b/src/routes/projects.js
@@ -22,12 +22,20 @@
 router.get('/api/projects', authenticate, async (req, res) => {
   try {
-    const projects = await Project.find({ orgId: req.user.orgId });
-    res.json(projects);
+    const page = parseInt(req.query.page) || 1;
+    const limit = parseInt(req.query.limit) || 25;
+    const offset = page * limit;
+
+    const [projects, totalCount] = await Promise.all([
+      Project.find({ orgId: req.user.orgId })
+        .skip(offset)
+        .limit(limit)
+        .sort({ updatedAt: -1 }),
+      Project.countDocuments({ orgId: req.user.orgId })
+    ]);
+
+    res.json({
+      data: projects,
+      pagination: {
+        page,
+        limit,
+        total: totalCount,
+        pages: Math.ceil(totalCount / limit)
+      }
+    });
   } catch (err) {
     res.status(500).json({ error: 'Failed to fetch projects' });
   }
 });
